# Replace with: Res = FindFirstInst();\n    // Check if the found instruction is in an unreachable block.\n    if (!DT->isReachableFromEntry(Res->getParent())) {\n      // Use the function entry as a safe insertion point.\n      BasicBlock &EntryBlock = F->getEntryBlock();\n      Res = &*EntryBlock.getFirstInsertionPt();\n      // Update BB to match.\n      BB = &EntryBlock;\n    }\n    EntryToLastInstruction.try_emplace(E, Res);
pattern5 = r'Res = FindFirstInst\(\);\n    EntryToLastInstruction\.try_emplace\(E, Res\);'
replacement5 = '''Res = FindFirstInst();
